public class Solution {
    public static long solve(long[] nums) {
        int maxIndex = nums.length - 1;
        boolean[] sieve = new boolean[maxIndex + 1];
        Arrays.fill(sieve, true);
        sieve[0] = false;
        sieve[1] = false;
        int sqrtMax = (int) Math.sqrt(maxIndex);
        for (int i = 2; i <= sqrtMax; i++) {
            if (sieve[i]) {
                for (int j = i * i; j <= maxIndex; j += i) {
                    sieve[j] = false;
                }
            }
        }
        long sumA = 0;
        long sumB = 0;
        for (int i = 0; i < nums.length; i++) {
            if (sieve[i]) {
                sumA += nums[i];
            } else {
                sumB += nums[i];
            }
        }
        return Math.abs(sumA - sumB);
    }
}
